class Solution {
public:
    bool canChange(string start, string target) {
        int n = start.length();
        int startL = 0, startR = 0, targetL = 0, targetR = 0;
        for (int i = 0; i < n; i++) {
            if (start[i] == 'L') startL++;
            if (start[i] == 'R') startR++;
            if (target[i] == 'L') targetL++;
            if (target[i] == 'R') targetR++;
        }
        if (startL != targetL || startR != targetR) return false;
        int startIdx = 0, targetIdx = 0;
        for (int i = 0; i < n; i++) {
            if (start[i] == 'L') {
                while (target[targetIdx] != 'L') targetIdx++;
                if (targetIdx < i) return false;
                targetIdx++;
            }
            if (start[i] == 'R') {
                while (target[targetIdx] != 'R') targetIdx++;
                if (targetIdx > i) return false;
                targetIdx++;
            }
        }
        return true;
    }
};

